/** 状态栏本地改动了 store 时置位，避免「初始化」检查点被同步写回污染 */
let localMutationUntil = 0;

export function markStatusBarLocalMutation(ms = 2500) {
  localMutationUntil = Date.now() + ms;
}

export function isStatusBarLocalMutation(): boolean {
  return Date.now() < localMutationUntil;
}

export async function withStatusBarMutation<T>(fn: () => T | Promise<T>): Promise<T> {
  markStatusBarLocalMutation();
  try {
    return await fn();
  } finally {
    markStatusBarLocalMutation();
  }
}
